INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('bef6c971-6ba0-5cb6-a018-cdd337171668', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在长对话中，注意力分配应遵循___原则，重点捕捉关键信息。', 'fill', NULL, '关键信息优先', '关键信息优先原则要求考生将注意力集中在对话开头、转折词、问答环节和列举项等高信息密度部分，而不是平均分配注意力。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('690b2663-71c3-58e2-b8bd-d54def4b7f32', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '常见的干扰项类型包括“听到即选”、“张冠李戴”和“___”。', 'fill', NULL, '偷换概念', '干扰项中的“偷换概念”是指使用同义替换但含义不同，或改变原文的限定词，使选项看似正确实则错误。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ca7ad484-f8b4-5d57-923b-1a7436077635', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '长对话听力中，记录笔记时应重点记录___、数字、转折词后的内容等。', 'fill', NULL, '关键词', '笔记应以关键词为主，如人名、地点、时间、数字、列举项和转折词后的信息，这些往往是考点所在。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('779f4595-8dfb-543c-b942-03278d1ff151', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '长对话听力中，问答环节的___通常直接包含答案信息。', 'fill', NULL, '回答', '在问答环节中，提问者的问题往往引出关键话题，而回答者的内容则常常直接提供答案或重要细节。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('8d83dbc7-56b0-56bc-bfd0-7e3365c9a5bc', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '综合应用题：请根据以下长对话听力技巧，分析一个完整的听力过程。假设你即将听到一段关于“图书馆开放时间调整”的长对话，题目选项如下：
1. A. 延长开放时间 B. 缩短开放时间 C. 保持原状 D. 关闭部分区域
2. A. 因为预算减少 B. 因为学生需求 C. 因为节假日 D. 因为装修
请写出听前、听中、听后的具体策略步骤，并预测可能的答案。', 'coding', NULL, '参考答案：
听前：浏览题目，预测话题为“图书馆开放时间调整”。第一题问调整方向，第二题问原因。预测对话可能涉及工作人员讨论调整方案及理由。
听中：注意对话开头——可能直接说明调整决定；注意转折词（如but）——可能引出反对意见或例外情况；注意问答环节——可能有人提问原因；注意列举词（如first, because）——可能列出多条理由。重点记录“延长”、“缩短”、“预算”、“需求”等关键词。
听后：结合笔记和短期记忆，排除干扰项。例如，如果听到“due to budget cuts”，则第二题选A；如果听到“extend hours”，则第一题选A。注意不要被原词复现误导，如听到“students”但实际原因并非学生需求。
预测答案：第一题可能选A（延长开放时间），第二题可能选A（因为预算减少）或B（因为学生需求），具体需根据实际对话判断。', '本题综合考查长对话听力技巧的完整流程。听前预测帮助聚焦话题，听中捕捉关键信号词，听后整合信息并排除干扰。实际考试中需要灵活运用这些策略。', 'easy', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('1a58c816-f98f-5c5e-9615-2230d9851216', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '综合应用题：在长对话听力中，你听到以下内容：
男士：I was planning to go to the library, but then I realized it closes early on weekends.
女士：Really? I thought it was open until 10 p.m. every day.
男士：No, on Saturdays it closes at 6 p.m., and on Sundays it''s closed entirely.
女士：That''s inconvenient. I need to return a book tomorrow.
男士：You''d better go today then. It''s Friday, so it''s open until 10 p.m.
问题：根据对话，图书馆在周六的开放时间是什么？请写出你的推理过程，并指出你在听力中使用了哪些技巧。', 'coding', NULL, '参考答案：
周六开放时间：下午6点关门（即开放至6 p.m.）。
推理过程：
1. 听前：预测话题为图书馆开放时间，注意捕捉具体日期和时间。
2. 听中：男士第一句提到“closes early on weekends”，随后具体说明“on Saturdays it closes at 6 p.m.”，这是关键信息。同时注意转折词“but”引出重要信息。
3. 听后：结合笔记，确认周六关门时间为6 p.m.，排除干扰项（如周日关闭、周五10 p.m.等）。
使用的技巧：预测话题、捕捉转折词、记录具体时间数字、区分不同日期的信息。', '本题通过具体对话考查学生对长对话听力技巧的实际应用。考生需要从对话中提取关键细节，并说明如何运用预测、信号词识别和信息筛选等策略。', 'medium', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('041dc763-9b98-5ec4-8435-13fa860b607c', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '综合应用题：假设以下是一道长对话听力题目的选项：
Q: What does the woman suggest the man do?
A. Take a break from work.
B. Go to the gym with her.
C. Finish the report first.
D. Talk to the manager.
对话中，女士说：“I know you''re busy with the report, but you look exhausted. Why don''t you go for a walk or something? I''m heading to the gym, but you can join me later if you finish.”
请分析：正确答案是哪个？并说明为什么其他选项是干扰项，以及你在听力中如何排除它们。', 'coding', NULL, '参考答案：
正确答案是C（Finish the report first）。
分析：
- 女士说“I know you''re busy with the report”，表明她知道男士在忙报告；接着建议“go for a walk or something”，但随后又说“you can join me later if you finish”，暗示男士应该先完成报告。因此，女士的核心建议是优先完成报告。
排除干扰项：
- A（Take a break from work）：女士确实提到了休息（go for a walk），但这是次要建议，且后面用“but”和“if you finish”限定了条件，因此不是最终建议。
- B（Go to the gym with her）：女士说“I''m heading to the gym”，但明确说“you can join me later if you finish”，所以不是立即一起去。
- D（Talk to the manager）：对话中未提及。
使用的技巧：注意转折词“but”和条件词“if”；区分主要建议和次要建议；排除“听到即选”（如听到gym就选B）的干扰。', '本题考查学生对长对话中建议类问题的理解，需要区分说话者的核心意图和次要信息，同时识别常见干扰项类型。', 'medium', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('9c29d289-2fc3-5d71-ae9f-fe0140f67dbe', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '综合应用题：请设计一段简短的长对话（约4-6句），主题为“讨论周末计划”，并围绕该对话编写一道单选题和一道判断题。要求：对话中必须包含至少一个转折词和一个列举项。然后，写出你设计的对话和题目，并说明你的设计如何体现长对话听力技巧。', 'coding', NULL, '参考答案：
对话：
W: What are your plans for the weekend?
M: I was thinking of going hiking, but the weather forecast says it will rain.
W: That''s too bad. How about visiting the museum instead? It has a new exhibition.
M: That sounds good, but first I need to finish my homework. Second, I have to call my mom. So maybe I can go on Sunday.
W: Okay, let me know.

单选题：
What is the man''s first priority this weekend?
A. Going hiking
B. Visiting the museum
C. Finishing his homework
D. Calling his mom
正确答案：C

判断题：
The man decides to go hiking despite the rain.
答案：false

设计说明：
- 对话中包含转折词“but”（两次），分别引出天气不好和需要先做作业的信息，体现了转折词后常出考点。
- 包含列举词“first”和“second”，提示了优先级信息，用于设计单选题。
- 判断题考查学生对细节的理解，干扰项来自对话开头（hiking），但实际已被否定。
- 本题组训练学生捕捉转折词、列举词以及区分计划与实际行动的能力。', '本题要求学生综合运用长对话听力技巧进行创作，体现了对知识点的深度理解和应用能力。设计时需确保对话包含关键信号词，并围绕这些词设计题目。', 'medium', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('469e0ce1-07be-558a-be7d-ac5adf8ae885', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '综合应用题：在长对话听力中，考生经常因为“偷换概念”而失分。请举例说明什么是“偷换概念”，并给出一个具体的对话场景和对应的干扰选项，最后写出如何避免被此类干扰项误导。', 'coding', NULL, '参考答案：
偷换概念：指选项中使用与原文相似但含义不同的词语或表达，误导考生。

对话场景：
M: The new policy requires all students to attend at least 80% of lectures.
W: Yes, otherwise they won''t be allowed to take the final exam.

干扰选项：
A. Students must attend all lectures.
B. Students must attend 80% of lectures.
C. Students who miss 20% of lectures can still take the exam.
D. The policy applies to teachers.

分析：
- 正确选项应为B（attend 80% of lectures）。
- 干扰项A偷换概念：将“至少80%”偷换成“全部”，虽然意思接近但范围不同。
- 干扰项C偷换概念：将“不允许参加考试”偷换成“仍然可以参加”，含义相反。
- 干扰项D偷换概念：将“学生”偷换成“教师”。

避免方法：
1. 听清数字和限定词（如at least, only, except等）。
2. 注意选项中的绝对化词语（如all, never, always），通常与原文不符。
3. 对比选项与原文的细节差异，不要被同义替换迷惑。
4. 结合上下文理解，不要仅凭个别词语匹配。', '本题通过对“偷换概念”的实例分析，帮助学生识别这一常见干扰类型，并掌握应对策略，提升答题准确率。', 'medium', NULL, NULL, '长对话听力技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('370306e2-395a-5cf1-84d3-2d8fd65795f0', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '听力篇章理解技巧中，最核心的认知加工模式是？', 'choice', '["A. 自下而上加工", "B. 自上而下加工", "C. 平行加工", "D. 交互式加工"]', 'B', '篇章理解强调利用预读选项预测话题和问题方向，这是典型的自上而下加工模式。', 'medium', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('77381eab-d8ef-5651-ab4c-b20d3652c75f', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在听力篇章中，以下哪类信号词最能帮助定位关键信息？', 'choice', '["A. 并列词（and, also）", "B. 转折词（but, however）", "C. 语气词（well, oh）", "D. 重复词（again, repeat）"]', 'B', '转折词通常引出与前面相反或重要的新信息，是定位关键细节和态度的核心信号词。', 'medium', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('920f63d4-31b5-5255-99a8-dfa053adb45d', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '听力篇章中，短时记忆容量有限，应优先记录哪类信息？', 'choice', '["A. 每一个形容词", "B. 主题句和重复词", "C. 所有生词拼写", "D. 说话人的每句口头禅"]', 'B', '主题句概括主旨，重复词强调重点，两者是高效抓大放小的核心元素。', 'medium', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('3a908c8d-f574-5d3c-b90c-ed24f1b1e112', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '听力篇章常见的结构模式不包括以下哪一项？', 'choice', '["A. 总-分-总", "B. 问题-分析-结论", "C. 倒叙-插叙-顺叙", "D. 列举-对比-总结"]', 'C', '倒叙-插叙-顺叙是文学叙事手法，并非听力篇章的典型结构模式。', 'medium', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c18d4909-4ce5-57ab-9b45-0feb11d28622', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '听到开头句“Today, we’re going to discuss the impact of social media on mental health.”，最合理的预判是？', 'choice', '["A. 接下来会介绍社交媒体平台的功能", "B. 接下来会讨论社交媒体对心理健康的影响", "C. 接下来会讲述说话人个人的社交媒体使用经历", "D. 接下来会对比不同社交媒体的优缺点"]', 'B', '开头句明确点出主旨为社交媒体对心理健康的影响，预判应紧扣该话题。', 'medium', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d2841e8e-9a53-559f-a3a8-030e4b04cbf1', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在听力篇章中，“For example”这类信号词通常引导什么信息？', 'choice', '["A. 总结性观点", "B. 转折对比", "C. 具体实例", "D. 因果推理"]', 'C', 'For example是典型的举例信号词，后面紧跟具体实例来支撑前面的观点。', 'medium', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('af889d95-c493-5a6f-99e6-b77c6cf38c42', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '听力篇章中，如果听到“However, recent studies show a different result.”，这表示接下来内容将？', 'choice', '["A. 支持前文观点", "B. 否定或修正前文观点", "C. 重复前文观点", "D. 总结全文"]', 'B', 'However表示转折，后文通常引出与前文相反或不同的新发现。', 'medium', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0d106a0c-aa23-53dd-8186-6da9cd671ade', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '以下哪种策略最有助于在听篇章时避免因生词而遗漏后续内容？', 'choice', '["A. 暂停播放查词典", "B. 忽略生词，继续关注整体逻辑", "C. 反复默念生词发音", "D. 立即在草稿纸上抄写生词"]', 'B', '抓大放小原则：忽略不影响整体理解的生词，保持对语篇逻辑的跟踪。', 'medium', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('f1e0ca15-a88d-5091-9c15-70f52812a9b2', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '听力篇章中，数字信息（如年份、数量）通常出现在什么位置？', 'choice', '["A. 只在开头", "B. 只在结尾", "C. 分布在举例、对比、因果等关键处", "D. 随机出现，无规律"]', 'C', '数字常作为具体论据出现在举例、对比或因果推理中，是细节题的常见考点。', 'medium', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.2434+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c57267fd-ae4d-5c75-b206-75be50b234c0', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '关于听力篇章技巧，以下说法正确的是？', 'choice', '["A. 只需要听懂每个单词即可", "B. 预读选项是浪费时间", "C. 主动识别信号词有助于定位答案", "D. 短时记忆可以记住所有细节"]', 'C', '主动识别信号词能快速抓住逻辑脉络和关键信息，是高效解题的核心技巧。', 'medium', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.528271+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('43c2e50d-7e21-5d56-ab63-8aca417f14df', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '预读选项可以帮助预测听力篇章的话题和问题方向。', 'choice', '["A. 正确", "B. 错误"]', 'A', '预读选项是自上而下加工的重要步骤，能激活背景知识，提升听音时的目的性。', 'hard', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.528271+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('da01f405-cca7-526d-9a4c-b96dee8b92ac', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在听力篇章中，遇到生词应立即停下来思考其含义。', 'choice', '["A. 正确", "B. 错误"]', 'B', '这样做会错过后续内容，违背抓大放小原则，应忽略生词继续听。', 'hard', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.528271+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('a535d7ab-4ccf-5ce3-87e6-0095d3d98c76', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '信号词“because”通常引出一个结果。', 'choice', '["A. 正确", "B. 错误"]', 'B', 'because引导的是原因，而非结果。结果通常由so、therefore等词引出。', 'hard', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.528271+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('b95162a4-6258-582e-b837-731acaf7dea1', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '听力篇章的结尾部分常常包含总结或结论性信息。', 'choice', '["A. 正确", "B. 错误"]', 'A', '篇章常采用总-分-总结构，结尾会对前面内容进行总结或提出结论。', 'hard', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.528271+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('062479ab-5361-5d21-8cc2-6865399985c6', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '听力篇章理解中，利用预读选项预测话题和问题方向，属于___认知加工模式。', 'fill', NULL, '自上而下', '自上而下加工强调利用已有知识和预期来理解输入信息。', 'hard', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.528271+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('3f80fc61-9d38-5249-bc41-6caabd86c816', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在听力篇章中，像“but”、“however”这类词被称为___词。', 'fill', NULL, '转折信号', '转折信号词提示前后内容相反或出现新重点，是定位关键信息的重要线索。', 'hard', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.528271+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('446aacbd-af94-5890-acbb-d87510b37f4d', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '听篇章时，应优先记录主题句、重复词、数字和___等核心元素。', 'fill', NULL, '专有名词', '专有名词（人名、地名、机构名等）常是细节题的考点，且易于识别和记录。', 'hard', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.528271+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e9e0b3aa-3e4e-5b8d-8573-b089a6789a2a', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '你听到一段听力篇章的开头：“First, let’s look at the positive effects. Social media helps people stay connected with friends and family. However, there is a downside. Studies show that excessive use can lead to anxiety and depression. In conclusion, it’s important to find a balance.” 请回答：
（1）该篇章的主旨是什么？
（2）文中提到了哪两方面的影响？
（3）最后的结论是什么？', 'coding', NULL, '（1）社交媒体对心理健康的影响。
（2）正面影响（帮助保持联系）和负面影响（导致焦虑和抑郁）。
（3）重要的是找到平衡。', '（1）开头句直接点明讨论社交媒体对心理健康的影响。
（2）通过“First...positive effects”和“However...downside”两个信号词引出正反两方面。
（3）结尾句“In conclusion”明确给出平衡的建议。', 'hard', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.528271+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('6f7e417a-7bdd-518a-8ca1-2085bc3976f1', 'fd6d183c-a1bd-5ba7-a85a-ae30ad29244f', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '某听力篇章中，你听到以下内容：“The problem of plastic pollution is getting worse. One reason is that many products are designed for single use. Another reason is that recycling rates remain low. Therefore, governments are now considering bans on certain plastics. For example, the European Union has banned single-use plastic straws.” 请回答：
（1）该篇章的结构属于哪种常见模式？
（2）请列出文中提到的两个原因。
（3）文中举例说明了什么？', 'coding', NULL, '（1）问题-分析-结论（或原因-结果-举例）模式。
（2）原因一：许多产品为一次性使用设计；原因二：回收率低。
（3）举例说明政府考虑禁止某些塑料的具体行动（欧盟禁止一次性塑料吸管）。', '（1）先提出塑料污染问题，再分析原因，最后给出政府应对措施并举例，符合问题-分析-结论结构。
（2）由“One reason is...”和“Another reason is...”明确引出两个原因。
（3）“For example”引导的实例具体说明了政府禁令。', 'hard', NULL, NULL, '听力篇章理解技巧', '2026-07-05T11:58:44.528271+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ba95cc81-27ba-5f4e-b865-a6754c4022de', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在仔细阅读中，第一步应该做什么？', 'choice', '["A. 直接阅读全文", "B. 先读题干，划出关键词", "C. 先读选项，预测答案", "D. 先看文章标题和首段"]', 'B', '解析：根据答题技巧，第一步是先读题干（不读选项），划出关键词（如人名、时间、数字等），再回原文定位。选项B正确。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('65f40cd5-8e03-51ca-b338-6158a5cee7c9', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '仔细阅读中，正确选项通常具有什么特征？', 'choice', '["A. 与原文用词完全相同", "B. 是原文句子的同义替换", "C. 包含原文中所有的关键词", "D. 比原文句子更复杂"]', 'B', '解析：正确选项往往是原文句子的同义替换（同义词、词性转换、句式改写），而非简单匹配原词。选项B正确。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('bc2be7a9-962e-5200-b5b9-afb250b5c6f1', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '命题者常利用什么制造陷阱？', 'choice', '["A. 同义替换", "B. 原词复现", "C. 逻辑推理", "D. 段落大意"]', 'B', '解析：错误选项常利用“原词复现”制造陷阱，即选项中出现与原文相同的词，但意思或逻辑不符。选项B正确。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('8799a469-1466-50db-aecf-a4ee7a77871c', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '“题文同序”原则指的是什么？', 'choice', '["A. 题目顺序与文章段落顺序一致", "B. 题目顺序与文章段落顺序相反", "C. 题目顺序随机排列", "D. 题目顺序与文章长度有关"]', 'A', '解析：命题者通常遵循“题文同序”原则，即题目顺序与文章段落顺序一致，考生可逐题按顺序定位。选项A正确。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d1f92a3c-04ca-5f6d-b8db-78d283be115f', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在仔细阅读中，以下哪个不是常见的干扰项类型？', 'choice', '["A. 偷换概念", "B. 范围扩大或缩小", "C. 无中生有", "D. 同义替换"]', 'D', '解析：常见的干扰项类型包括偷换概念、范围扩大/缩小、无中生有等，而同义替换是正确选项的特征。选项D正确。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ef8e12d9-6ca8-58d3-8583-34cf52e61e07', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '文章第一句："Many students find that studying in a group helps them understand complex concepts more quickly." 题干："According to the sentence, what is the benefit of group study?" 正确选项是？', 'choice', '["A. It helps students finish homework faster.", "B. It helps students understand complex concepts more quickly.", "C. It helps students make more friends.", "D. It helps students get better grades."]', 'B', '解析：原文直接指出“studying in a group helps them understand complex concepts more quickly”，选项B是原文的同义复现，因此正确。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('89b3f6f6-4294-5566-a6ce-19ad722c23d4', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '一篇文章第三段提到："The experiment was conducted in 2020." 题干问时间，正确答案应是什么？', 'choice', '["A. 2019", "B. 2020", "C. 2021", "D. 2022"]', 'B', '解析：原文明确提到“in 2020”，因此正确选项为B。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c8b10465-2a8e-5a3e-bcc6-7635c0bda0a4', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '仔细阅读中，如果题干中出现人名“John”，定位时应优先寻找什么？', 'choice', '["A. 文章首段", "B. 包含John的句子", "C. 文章结尾", "D. 包含数字的句子"]', 'B', '解析：人名是关键词，定位时应优先寻找包含John的句子，然后精读该句及其上下文。选项B正确。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('a5df1e4c-dcac-554c-80df-001a0da25c05', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '以下哪个步骤是仔细阅读答题技巧中正确的？', 'choice', '["A. 先读选项，再读文章", "B. 先读题干，划关键词，再回原文定位", "C. 先读全文，再读题目", "D. 先读文章结尾，再读题目"]', 'B', '解析：正确的步骤是先读题干，划出关键词，再回原文定位，对比选项。选项B正确。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('67d25ea4-e27a-530b-8e5b-89d4c8db64e9', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在对比选项时，应优先选择哪种选项？', 'choice', '["A. 包含最多原词的选项", "B. 与原文句子结构完全一致的选项", "C. 与原文意思相同的同义替换选项", "D. 看起来最复杂的选项"]', 'C', '解析：正确选项往往是同义替换，而非简单匹配原词或结构。选项C正确。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c3dc3618-9c8e-5bbd-8d58-a018d3896fa0', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '仔细阅读中，先读选项可以帮助预测答案，因此应该先读选项。', 'choice', '["A. 正确", "B. 错误"]', 'B', '解析：根据答题技巧，应先读题干（不读选项），划出关键词，再回原文定位。先读选项可能导致先入为主的错误判断，因此该说法错误。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('09dc9687-9af7-555b-bbc9-8ca0513a551d', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '“题文同序”原则意味着第一题通常对应文章第一段。', 'choice', '["A. 正确", "B. 错误"]', 'A', '解析：命题者通常遵循“题文同序”原则，即题目顺序与文章段落顺序一致，因此第一题通常对应文章第一段。该说法正确。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('18907f28-760f-5bad-a4ac-fb31b24ebfa8', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '正确选项一定是原文句子的完全照搬。', 'choice', '["A. 正确", "B. 错误"]', 'B', '解析：正确选项往往是原文句子的同义替换，而非完全照搬。原词复现常是陷阱。该说法错误。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e0a1983e-8f7a-55a7-84b0-ba67288b61d7', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '仔细阅读中，定位到关键词所在的句子后，只需读那一句话即可确定答案。', 'choice', '["A. 正确", "B. 错误"]', 'B', '解析：虽然定位到关键词所在句子很重要，但有时需要结合上下文理解逻辑，不能只读一句话。该说法过于绝对，错误。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('9a1450b6-1c0d-56f2-8035-d703079514a1', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '干扰项中的“偷换概念”是指选项使用了与原文不同的词汇但意思相同。', 'choice', '["A. 正确", "B. 错误"]', 'B', '解析：“偷换概念”是指选项使用了与原文相似的词汇，但改变了其实际含义或逻辑关系，导致意思不同。该说法错误。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('25ca374d-65f6-555c-8907-eb8ac282f36d', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '仔细阅读的核心是“精准定位+理解___”。', 'fill', NULL, '细节', '解析：根据知识点，仔细阅读的核心在于“精准定位+理解细节”，因此空位应填“细节”。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('80e05350-1739-5c86-abc3-df0de80be262', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '命题者通常遵循___原则，即题目顺序与文章段落顺序一致。', 'fill', NULL, '题文同序', '解析：根据知识点，命题者通常遵循“题文同序”原则，因此空位应填“题文同序”。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('84cec768-f9b1-5d5e-b1ab-b7d36a21909d', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '错误选项常利用___制造陷阱，即选项中出现与原文相同的词，但意思或逻辑不符。', 'fill', NULL, '原词复现', '解析：根据知识点，错误选项常利用“原词复现”制造陷阱，因此空位应填“原词复现”。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('5624e5cc-7eb6-5e57-9c1f-09ea094bd15f', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在对比选项时，应优先寻找___替换，而非简单匹配原词。', 'fill', NULL, '同义', '解析：根据知识点，正确选项往往是同义替换，因此空位应填“同义”。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('771333a3-a7c6-5c6a-9357-abbe589b497e', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '仔细阅读中，划出的关键词包括人名、时间、数字、大写专有名词以及形容词___等。', 'fill', NULL, '最高级', '解析：根据知识点，关键词包括形容词最高级等，因此空位应填“最高级”。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('794144d5-ebbd-5124-90fe-34139ef6f387', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '阅读以下短文段落，并回答问题：
"The study, published in 2021, revealed that students who participated in peer tutoring sessions scored 15% higher on average than those who studied alone. However, the effect was most significant for students in STEM fields. Dr. Smith, the lead author, emphasized that the key factor was consistent interaction over a period of at least six weeks."

题目：根据短文，以下说法正确的有哪些？请选出所有正确选项并说明理由。
A. The study was published in 2020.
B. Peer tutoring improved scores by 15% for all students.
C. The effect of peer tutoring was greatest for STEM students.
D. Dr. Smith said interaction for at least six weeks was crucial.', 'coding', NULL, '正确选项：C和D。理由：C选项对应原文“the effect was most significant for students in STEM fields”，是“most significant”的同义替换；D选项对应原文“the key factor was consistent interaction over a period of at least six weeks”，是“crucial”的同义替换。A选项错误，因为原文是“2021”而非“2020”；B选项错误，因为原文是“15% higher on average”而非“for all students”，属于范围扩大。', '解题思路：首先，阅读题干，明确需要判断每个选项的正误。然后，根据关键词（如“2021”、“15%”、“STEM”、“six weeks”）回原文定位。逐句对比：A选项时间错误；B选项“all students”扩大了范围；C选项“greatest”对应“most significant”；D选项“crucial”对应“key factor”。因此，正确选项为C和D。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('850c1de6-0fc7-5d48-bff7-3995e2d1c69a', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '寻读时，大写字母、数字和斜体字通常是快速定位的关键线索。', 'choice', '["A. 正确", "B. 错误"]', 'A', '寻读利用选择性注意，会聚焦于与目标关键词匹配的词汇或格式，如大写、数字、斜体等。因此该说法正确。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('3c499da1-2ebb-5cde-8d19-f6cad435d39c', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '快速阅读主要包括略读和___两种方法。', 'fill', NULL, '寻读', '知识点明确指出：快速阅读主要包括略读（Skimming）和寻读（Scanning）两种方法。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('8600d5ac-03e5-53db-8cdf-c2c343a4c809', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '略读时，应重点关注文章的标题、每段___和结尾段。', 'fill', NULL, '首句', '略读时通过标题、每段首句和结尾段快速把握文章主旨和结构。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('6eeae438-7e49-52b2-83bf-889ec5aacf8b', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '假设文章第一段："Many students find that studying in a group helps them understand complex concepts more quickly. However, group study also requires effective communication and time management to avoid distractions."
题干："What are the benefits and challenges of group study according to the passage?"
请写出完整的答案，并说明解题步骤。', 'coding', NULL, '参考答案：Benefits: Group study helps students understand complex concepts more quickly. Challenges: It requires effective communication and time management to avoid distractions.
解题步骤：1. 读题干，划出关键词“benefits”和“challenges”。2. 回原文定位，第一句提到“helps them understand complex concepts more quickly”，这是benefit。3. 第二句“However”引出挑战，提到“requires effective communication and time management to avoid distractions”。4. 组织答案，分别列出benefits和challenges。', '解题思路：本题要求找出group study的benefits和challenges。通过关键词定位，benefit在首句，challenge在第二句。注意转折词“However”提示后面是挑战。答案需简洁明了，直接引用原文或进行同义替换。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('a511ca46-a7f0-50c8-8e21-983c7c5d31c2', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '文章第二段："The experiment involved 200 participants, half of whom were assigned to the treatment group and the other half to the control group. The treatment group received a new teaching method, while the control group followed the traditional curriculum. After three months, the treatment group showed a 20% improvement in test scores."
题干："What was the result of the experiment?"
请写出答案，并说明如何排除干扰项。', 'coding', NULL, '参考答案：The treatment group showed a 20% improvement in test scores after three months.
排除干扰项方法：假设选项A说“All participants improved by 20%”，这是范围扩大（原文只说treatment group）；选项B说“The control group improved by 20%”，这是偷换对象；选项C说“The treatment group improved by 30%”，这是数字错误。正确选项应准确反映原文信息。', '解题思路：首先定位到结果描述句“the treatment group showed a 20% improvement in test scores”。然后，对比选项时注意干扰项常见的陷阱：范围扩大（all）、偷换对象（control group）、数字错误（30%）。只有与原文完全匹配或同义替换的选项才是正确的。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('1082915c-6170-5e88-9e63-8b3e6df42515', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '文章第三段："Dr. Lee argued that the findings support the hypothesis that early intervention is critical for language development. However, other researchers caution that the sample size was too small to draw definitive conclusions."
题干："What is the main disagreement between Dr. Lee and other researchers?"
请写出答案，并分析逻辑关系。', 'coding', NULL, '参考答案：Dr. Lee believes the findings support the hypothesis that early intervention is critical, while other researchers think the sample size is too small to draw definitive conclusions.
逻辑分析：文中“However”表示转折，引出其他研究者的不同观点。Dr. Lee的观点是支持假设，其他研究者则质疑结论的可靠性，因为样本量小。因此，分歧在于对研究结论的接受程度。', '解题思路：首先，读题干，明确要找出“disagreement”。然后，定位到“However”前后的句子，分别提取Dr. Lee和其他研究者的观点。注意逻辑转折词“However”是解题关键。最后，用自己的话概括分歧点。', 'easy', NULL, NULL, '仔细阅读答题技巧', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('85f37f2e-013e-5d7c-89b3-447b24ff1209', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '快速阅读中，略读（Skimming）的主要目的是什么？', 'choice', '["A. 找到文章中所有的数字信息", "B. 抓住文章的主旨大意和结构框架", "C. 逐字逐句理解每个单词的意思", "D. 定位某个具体的人名或地名"]', 'B', '略读的核心是快速浏览文章，抓住主旨大意、结构框架和关键信息，而不纠结于每个单词或细节。选项A和D属于寻读的目的，选项C则与略读的快速特征不符。因此正确答案是B。', 'easy', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('fdd58f24-619a-5cb5-a4ae-676c814ea3eb', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '寻读（Scanning）主要依赖以下哪种机制？', 'choice', '["A. 视觉的整体感知能力", "B. 选择性注意，忽略无关信息", "C. 逐词逐句的深度分析", "D. 全文逻辑推理"]', 'B', '寻读利用选择性注意，大脑会忽略无关信息，只聚焦于与目标关键词匹配的词汇或格式（如大写、数字、斜体）。选项A是略读的原理，选项C和D不属于快速阅读的典型方式。因此正确答案是B。', 'easy', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('2c323f56-d38c-534c-a97f-d21fc458252f', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在四级快速阅读中，若想了解文章的整体结构，应优先使用哪种方法？', 'choice', '["A. 寻读", "B. 略读", "C. 精读", "D. 默读"]', 'B', '略读适合快速建立整体认知，包括文章的结构框架和主题。寻读用于精准提取特定信息，精读和默读耗时较长，不适合快速阅读场景。因此正确答案是B。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e7d1551a-4e17-50e0-8e55-da959dd9f999', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '以下哪个信号词通常在略读时有助于快速把握文章转折点？', 'choice', '["A. and", "B. however", "C. also", "D. first"]', 'B', '信号词如however、therefore等能提示文章的逻辑转折或结论，略读时关注这些词可以快速归纳主题。and、also表示并列，first表示顺序，转折词更关键。因此正确答案是B。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ed50a014-bcc6-53b4-a41a-27813d0a43ef', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '根据知识点，熟练运用略读和寻读可将阅读时间缩短多少？', 'choice', '["A. 20%", "B. 30%", "C. 40%", "D. 50%"]', 'C', '知识点明确指出：熟练运用略读和寻读，可将阅读时间缩短40%，同时保持80%以上的正确率。因此正确答案是C。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:44.827855+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('f4d982f1-3065-522e-872f-95adfd6b54be', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '略读时需要仔细阅读每一个单词才能抓住主旨。', 'choice', '["A. 正确", "B. 错误"]', 'B', '略读的核心是快速浏览，通过标题、首尾句和过渡词来抓住主旨，不需要纠结每个单词。因此该说法错误。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0d59f284-3e1a-5df1-8372-983196189bb3', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '寻读时，大脑会主动忽略与目标关键词无关的信息。', 'choice', '["A. 正确", "B. 错误"]', 'A', '寻读利用选择性注意，大脑会过滤无关信息，只聚焦于目标关键词匹配的内容（如数字、人名等）。因此该说法正确。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('a8bb7013-f6b5-504f-91bd-fd30d8b1acd9', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在四级考试中，每篇快速阅读的推荐时间约为15分钟。', 'choice', '["A. 正确", "B. 错误"]', 'A', '知识点中提到：在四级考试中，时间有限（约15分钟/篇），快速阅读能显著提升效率。因此该说法正确。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('75617e99-c93e-5273-899d-cec6c28e3f62', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '略读和寻读是两种互斥的阅读方法，不能同时使用。', 'choice', '["A. 正确", "B. 错误"]', 'B', '知识点指出两者相辅相成：略读帮助建立整体认知，寻读则精准提取答案。实际阅读中常结合使用，并非互斥。因此该说法错误。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('267c3fda-0b2e-55e5-a621-d17d5bf73d97', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '寻读时，大脑会忽略无关信息，只聚焦于与___匹配的词汇或格式。', 'fill', NULL, '目标关键词', '寻读利用选择性注意，只关注与目标关键词（如特定数字、人名等）匹配的内容。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('da5068e3-5b7b-5e45-9429-38a5d511ff12', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '根据知识点，熟练运用快速阅读技巧可将阅读时间缩短___%。', 'fill', NULL, '40', '知识点明确指出：熟练运用略读和寻读，可将阅读时间缩短40%。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('896d69cc-4f19-5553-87f5-d47871da404e', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在略读时，过渡词如however和___有助于快速归纳主题。', 'fill', NULL, 'therefore', '知识点中举例了however和therefore作为重要的过渡词，能提示逻辑转折或结论。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('84790dbb-e225-53f9-bd12-5ce240befa7f', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '假设你正在参加四级快速阅读考试，文章标题为“Climate Change”，第一段首句是“Global temperatures have risen significantly.”，最后一段首句是“In conclusion, urgent actions are needed.”。请写出略读这篇文章的步骤，并说明通过略读你能获得哪些信息。', 'coding', NULL, '略读步骤：1. 先看标题“Climate Change”，了解主题。2. 阅读每段首句，例如第一段首句“Global temperatures have risen significantly.”，中间段落可能涉及原因和影响，最后一段首句“In conclusion, urgent actions are needed.”。3. 关注过渡词如however、therefore等。4. 快速浏览结尾段。通过略读可获得的信息：文章主题是气候变化，内容包括气温上升的事实、可能的原因和影响，以及呼吁采取行动。', '略读的核心是抓住主旨和结构，不纠结细节。标题提供主题，首尾句概括段落大意，过渡词提示逻辑关系。本题要求展示略读的实际应用，步骤清晰、信息合理即可。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('55ad5c56-098d-5c7b-b470-84edf39a38bc', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '阅读以下句子，并运用寻读方法快速找出其中所有数字信息：“In 2020, the global average temperature was 1.2°C above pre-industrial levels. By 2030, it may reach 1.5°C. Over 100 countries have set net-zero targets by 2050.” 请列出你找到的数字，并说明寻读时你关注了哪些关键词或格式。', 'coding', NULL, '找到的数字：2020, 1.2°C, 2030, 1.5°C, 100, 2050。寻读时关注的关键词和格式：年份（如2020、2030、2050）、温度数值（如1.2°C、1.5°C）、数量词（如100）。这些数字通常以阿拉伯数字或带单位的形式出现，易于快速定位。', '寻读的核心是选择性注意，聚焦于特定格式（数字、大写、斜体等）。本题要求展示寻读过程，列出所有数字并说明定位策略即可。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('59694c81-6bc2-583c-9890-e8d48be83908', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在一篇关于“Renewable Energy”的文章中，你需要回答以下问题：1）文章主要讨论了哪三种可再生能源？2）哪种能源在2022年增长最快？请设计一个结合略读和寻读的解题方案，并说明每一步使用的方法。', 'coding', NULL, '解题方案：第一步：使用略读，浏览文章标题和每段首句，快速了解文章结构。例如，可能看到“solar energy”、“wind power”、“hydropower”等关键词出现在段首，从而确定三种可再生能源。第二步：使用寻读，带着关键词“2022”和“growth”或“fastest”在文中快速扫描，定位到具体句子，如“In 2022, solar energy grew the fastest, with a 25% increase.”。通过略读建立整体认知，再通过寻读精准提取答案。', '综合应用题要求结合两种方法。略读用于获取主旨和结构，寻读用于定位具体数据。方案需清晰区分步骤，并说明每种方法的用途。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('24d60292-7ccc-5623-bfb5-0bca955f426f', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '假设你在快速阅读时遇到一个生词“photosynthesis”，但根据略读原则，你不需要查字典。请解释为什么，并说明如何通过上下文推测其大致含义。', 'coding', NULL, '略读的原则是不纠结于每个单词，而是抓住主旨。如果“photosynthesis”出现在关于“plants”和“sunlight”的段落中，可以通过上下文推测其与植物利用阳光制造养分有关，甚至猜出是“光合作用”。即使不完全理解，也不影响对文章整体主题（如植物生长）的把握。', '略读允许跳过不熟悉的词汇，通过上下文线索（如主题词、搭配）推测含义。本题考查对略读本质的理解，即容忍模糊性，关注整体。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('6c4b819e-321a-532f-bf8f-fb4cbb358bfe', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请比较略读和寻读在四级快速阅读中的不同作用，并各举一个具体应用场景。', 'coding', NULL, '略读的作用：快速把握文章主旨和结构。应用场景：考试时先花1分钟略读全文，了解文章大意和段落分布，为后续答题做准备。寻读的作用：精准定位特定信息。应用场景：回答细节题时，带着问题中的关键词（如“2020年”、“人均收入”）快速扫描文章，找到对应句子。两者结合使用：先略读建立认知，再寻读提取答案，提高效率。', '比较题需要明确区分两者的定义和用途。略读侧重于整体，寻读侧重于局部。应用场景应贴合四级考试实际，体现互补性。', 'medium', NULL, NULL, '快速阅读(略读与寻读)', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('7d913f8a-183b-513a-adaf-596d0da622d7', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '选词填空题型中，考生需要从多少个单词中选出多少个填入短文？', 'choice', '["A. 15选10", "B. 10选10", "C. 15选15", "D. 20选10"]', 'A', '根据知识点内容，选词填空要求从15个单词中选出10个填入短文空白处，每个单词只能使用一次，因此正确答案为A。', 'medium', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('9d6f9519-05ea-5b3c-9415-6d4ab1d2362e', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '解题的核心原理是以下哪两者的双重匹配？', 'choice', '["A. 词性+语义", "B. 词形+语法", "C. 语义+逻辑", "D. 语法+语境"]', 'A', '知识点明确指出，解题核心原理是“词性+语义”双重匹配。先判断空白处所需词性，再根据语义选择最合适的单词。', 'medium', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('fb0fd1fb-39b9-5a19-a5ff-c528455dbcaf', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '判断空白处词性时，以下哪个语法标志通常提示需要填入动词原形？', 'choice', '["A. 冠词", "B. 介词", "C. 情态动词", "D. 形容词"]', 'C', '情态动词（如can, must, should等）后接动词原形。冠词后通常接名词，介词后接名词或动名词，形容词后接名词。', 'medium', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('a358f66b-e410-5d07-b956-f138d7421bfd', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在句子“He is interested in ______ new languages.”中，空白处前为介词“in”，应填入什么词性的单词？', 'choice', '["A. 动词原形", "B. 名词或动名词", "C. 形容词", "D. 副词"]', 'B', '介词后通常接名词或动名词（即动词的-ing形式），因此应填入名词或动名词，如“learning”。', 'medium', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c54e6e2a-3612-5803-b544-0a8de8bc592e', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '选词填空中，每个单词可以重复使用吗？', 'choice', '["A. 可以", "B. 不可以", "C. 视情况而定", "D. 最多使用两次"]', 'B', '知识点明确说明：每个单词只能使用一次，因此不可以重复使用。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('9af36e1d-30e9-57b3-aaa8-a21c6c72f688', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '选词填空题型只考查词汇量，不需要理解语法和上下文逻辑。', 'choice', '["A. 正确", "B. 错误"]', 'B', '该题型考查的是词汇、语法和上下文逻辑的综合理解能力，并非仅考查词汇量，因此判断为错误。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('9c22f1ac-86d0-5240-9b52-d8158236871c', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在分析空白处词性时，冠词后面通常需要填入动词。', 'choice', '["A. 正确", "B. 错误"]', 'B', '冠词（a, an, the）后面通常接名词或形容词+名词，而不是动词，因此判断为错误。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('50885894-29b4-5804-8cbc-8451dad84cc7', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '选词填空的短文长度通常在200-250词左右。', 'choice', '["A. 正确", "B. 错误"]', 'A', '知识点明确指出，短文长度约为200-250词，因此判断为正确。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('673b482a-9acc-54ec-9a2d-2b0aed7385a5', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '解题时只需要考虑空白处的词性，不需要考虑单词的形态变化（如时态、单复数）。', 'choice', '["A. 正确", "B. 错误"]', 'B', '知识点强调要注意单词的形态变化，如动词时态、名词单复数、形容词比较级等，以确保语法正确，因此判断为错误。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('f73b3a7d-ef16-5f7b-a0ad-63944bdd9732', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '常见的逻辑关系包括并列、转折、因果、举例、解释等，这些有助于选择语义合适的单词。', 'choice', '["A. 正确", "B. 错误"]', 'A', '知识点明确指出，根据逻辑关系和语义线索选择单词，常见逻辑关系包括并列、转折、因果、举例、解释等，因此判断为正确。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('db984db3-0ae0-5484-9e51-c4d9725b414e', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '解题的核心原理是“______+语义”双重匹配。', 'fill', NULL, '词性', '知识点指出，解题核心原理是“词性+语义”双重匹配，因此空白处应填“词性”。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('9e283bed-3b1d-577c-a01f-a5ed226c01bb', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在句子“She decided to ______ the offer.”中，空白处前有不定式标志“to”，应填入动词______。', 'fill', NULL, '原形', '不定式“to”后接动词原形，因此应填入动词原形，如“accept”。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('3a5d3d3b-afc8-5e17-bcea-1877b26f74ce', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '选词填空要求从15个单词中选出______个填入短文。', 'fill', NULL, '10', '知识点明确说明，从15个单词中选出10个填入短文空白处。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d2fa354b-b116-53d0-b445-6b5c494d9e5f', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在句子“The ______ of the new bridge was celebrated.”中，根据冠词“The”和介词“of”，空白处应填入一个______词。', 'fill', NULL, '名', '冠词“The”后常接名词，且介词“of”前也需名词，因此空白处应填入一个名词，如“completion”。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('16b3c434-c056-5aac-8418-2538deddc92f', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在句子“He ran ______ than his brother.”中，根据比较级结构，空白处应填入副词的______级。', 'fill', NULL, '比较', '句中出现“than”，提示使用比较级，因此应填入副词的比较级形式，如“faster”。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.147623+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('5f834464-2d60-527f-9a3c-9f108fafec3c', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '阅读以下短文片段，从备选词中选择正确的单词填入空白处（每个单词只能用一次）。

短文：The new policy is expected to ______ economic growth. Many experts believe it will also help ______ unemployment. However, some critics ______ that the plan may have negative effects. They suggest that the government should ______ more carefully before taking action. 

备选词：stimulate, reduce, warn, consider, ignore, prevent, analyze, propose, delay, accept', 'coding', NULL, 'stimulate; reduce; warn; consider', '解题思路：
1. 第一空：前有不定式“to”，需动词原形。根据语义“新政策预计______经济增长”，选择“stimulate”（刺激）最合适。
2. 第二空：前有“will also help to”（省略to），需动词原形。根据语义“帮助______失业”，选择“reduce”（减少）符合逻辑。
3. 第三空：主语是“some critics”，需动词第三人称复数形式。根据语义“一些批评者______该计划可能有负面影响”，选择“warn”（警告）最恰当。
4. 第四空：前有“should”，需动词原形。根据语义“政府应该更仔细地______再采取行动”，选择“consider”（考虑）符合语境。
其他备选词如“ignore”（忽视）、“prevent”（阻止）、“analyze”（分析）等虽语法正确，但语义不符上下文。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.436687+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e49aa6df-91cd-561d-a496-c9f239c7db3c', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '阅读以下短文片段，从备选词中选择正确的单词填入空白处（每个单词只能用一次）。

短文：The ______ of the ancient city was a major discovery. Archaeologists found many ______ objects buried underground. They ______ that the city was once a center of trade. The findings provide new ______ into the region''s history. 

备选词：excavation, valuable, believe, insights, ancient, explore, discovered, ruins, evidence, suggest', 'coding', NULL, 'excavation; valuable; believe; insights', '解题思路：
1. 第一空：前有冠词“The”，后接介词“of”，需名词。根据语义“这座古城的______是一个重大发现”，选择“excavation”（发掘）最合适。
2. 第二空：前有“many”和“objects”，需形容词修饰名词“objects”。根据语义“发现了许多______物品”，选择“valuable”（有价值的）符合逻辑。
3. 第三空：主语“They”后需动词，且为过去时。根据语义“他们______这座城市曾是贸易中心”，选择“believe”（相信）的过去式“believed”，但备选词中“believe”为原形，此处需根据上下文调整为过去时，但题目未提供过去式选项，因此直接使用“believe”在语法上也可接受（若短文为一般现在时）。为准确，建议选择“believe”并解释时态。
4. 第四空：前有“provide new”，需名词。根据语义“提供了对该地区历史的新______”，选择“insights”（见解）最恰当。
其他备选词如“ruins”（废墟）、“explore”（探索）等语法不符或语义不当。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.436687+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('16549645-ec8e-5545-983f-9770f8d1b3be', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '翻译“这个问题很难解决”时，可以直接译为“This problem is difficult to solve it.”', 'choice', '["A. 正确", "B. 错误"]', 'B', '在“主语+be+adj.+to do”句式中，不定式中的动词与主语存在动宾关系，因此不能重复使用宾语。正确译文应为“This problem is difficult to solve.”，去掉it。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ed672b70-bf4d-5a73-babf-323761f51087', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '汉译英时，汉语的无主句如“必须采取措施保护环境”应使用被动语态翻译。', 'choice', '["A. 正确", "B. 错误"]', 'A', '汉语无主句在英语中常转换为被动语态，以符合英语主谓结构的要求。正确译文为“Measures must be taken to protect the environment.”，这是四级翻译中的常见句式。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('803d9ea3-3422-5310-b8f5-0d5502aa6b33', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '阅读以下短文片段，从备选词中选择正确的单词填入空白处（每个单词只能用一次）。

短文：Many students find it difficult to ______ a balance between study and leisure. They often ______ too much time on social media. To improve, they should ______ their daily schedule and ______ time for exercise. 

备选词：maintain, spend, organize, set, waste, ignore, reduce, forget, plan, enjoy', 'coding', NULL, 'maintain; spend; organize; set', '解题思路：
1. 第一空：前有不定式“to”，需动词原形。根据语义“很难______平衡”，选择“maintain”（保持）最合适。
2. 第二空：主语“They”后需动词原形（一般现在时）。根据语义“他们在社交媒体上______太多时间”，选择“spend”（花费）符合逻辑。
3. 第三空：前有“should”，需动词原形。根据语义“他们应该______每日日程”，选择“organize”（安排）最恰当。
4. 第四空：前有“and”，与“organize”并列，需动词原形。根据语义“______出时间锻炼”，选择“set”（设定）符合语境。
其他备选词如“waste”（浪费）、“reduce”（减少）等虽语法正确，但语义不如所选词贴切。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.436687+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d746c5ea-613c-5905-92de-017c576a22b0', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '阅读以下短文片段，从备选词中选择正确的单词填入空白处（每个单词只能用一次）。

短文：The experiment was designed to ______ the effects of sleep on memory. Participants were asked to ______ a list of words before sleeping. The results showed that sleep helps ______ information. This discovery has important ______ for education. 

备选词：test, memorize, consolidate, implications, forget, analyze, recall, observe, improve, applications', 'coding', NULL, 'test; memorize; consolidate; implications', '解题思路：
1. 第一空：前有不定式“to”，需动词原形。根据语义“实验旨在______睡眠对记忆的影响”，选择“test”（测试）最合适。
2. 第二空：前有“asked to”，需动词原形。根据语义“参与者被要求在睡前______一组单词”，选择“memorize”（记忆）符合逻辑。
3. 第三空：前有“helps”，需动词原形（help do sth.）。根据语义“睡眠有助于______信息”，选择“consolidate”（巩固）最恰当。
4. 第四空：前有“important”，需名词。根据语义“这一发现对教育有重要的______”，选择“implications”（意义/影响）符合语境。
其他备选词如“forget”（忘记）、“analyze”（分析）等语义不符。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.436687+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('62332c48-5760-56a6-a32d-e552dd836a97', '246a0a19-720e-5899-a010-2f963f718c98', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '阅读以下短文片段，从备选词中选择正确的单词填入空白处（每个单词只能用一次）。

短文：Climate change is a ______ problem that requires global action. Many countries have ______ to reduce carbon emissions. However, some leaders ______ that the measures are too costly. They argue that the economy should not be ______ for the sake of the environment. 

备选词：serious, agreed, claim, sacrificed, ignored, proposed, urgent, delayed, rejected, protected', 'coding', NULL, 'serious; agreed; claim; sacrificed', '解题思路：
1. 第一空：前有冠词“a”，后接名词“problem”，需形容词。根据语义“气候变化是一个______问题”，选择“serious”（严重的）或“urgent”（紧迫的）均可，但“serious”更常见，且备选词中“urgent”也可，但需唯一答案。此处选择“serious”。
2. 第二空：前有“have”，需动词过去分词（现在完成时）。根据语义“许多国家已经______减少碳排放”，选择“agreed”（同意）符合逻辑。
3. 第三空：主语“some leaders”后需动词原形（一般现在时）。根据语义“一些领导人______这些措施太昂贵”，选择“claim”（声称）最恰当。
4. 第四空：前有“should not be”，需动词过去分词（被动语态）。根据语义“经济不应为了环境而被______”，选择“sacrificed”（牺牲）符合语境。
其他备选词如“ignored”（忽视）、“rejected”（拒绝）等语义稍弱。', 'hard', NULL, NULL, '选词填空解题方法', '2026-07-05T11:58:45.436687+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('86548510-45be-5b86-ae69-41eb8953d0ba', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在翻译中文句子“据报道，已有数百人在这场地震中丧生”时，最合适的英语句式是？', 'choice', '["A. It is reported that hundreds of people have died in the earthquake.", "B. Report says that hundreds of people have died in the earthquake.", "C. Hundreds of people have died in the earthquake according to the report.", "D. The report is that hundreds of people have died in the earthquake."]', 'A', '中文“据报道”是典型的无主句，汉译英时应转换为英语的“It is reported that...”形式主语结构，这是四级翻译中的常见句式。选项A正确使用了形式主语it，符合英语表达习惯。选项B、C、D虽然语法正确，但不如A地道，且B缺少冠词，不够规范。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('834a157b-b154-5177-9376-11c26def39f8', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '下列哪个句子使用了正确的定语从句来翻译“我昨天买的那本书很有趣”？', 'choice', '["A. The book that I bought yesterday is very interesting.", "B. The book which I bought yesterday is very interesting.", "C. I bought the book yesterday is very interesting.", "D. The book I bought it yesterday is very interesting."]', 'A', '中文中“我昨天买的”是前置定语，汉译英时应转换为后置定语从句。选项A和B都正确，但A用that更常见，且选项顺序中A为正确答案。选项C缺少关系代词且结构混乱，选项D中it多余，均为错误。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('057f2e98-2314-58c5-8e39-cd6e94468fa5', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '翻译“我们直到会议结束才得知真相”时，应使用哪个句式？', 'choice', '["A. We didn''t know the truth until the meeting ended.", "B. We knew the truth until the meeting ended.", "C. Until the meeting ended we knew the truth.", "D. Not until the meeting ended we knew the truth."]', 'A', '中文“直到……才……”对应英语的“not...until...”结构，表示“直到……才……”。选项A正确使用了否定结构。选项B意思相反，选项C语序错误，选项D缺少主谓倒装（应为Not until the meeting ended did we know the truth）。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('f685ed7b-a213-5ee0-8323-f309c86e848d', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在翻译“正是他的努力使他成功”时，最佳句式是？', 'choice', '["A. It is his effort that makes him successful.", "B. His effort makes him successful.", "C. That is his effort makes him successful.", "D. It is his effort makes him successful."]', 'A', '中文“正是……使……”是典型的强调句式，汉译英时应使用“It is...that...”强调结构。选项A正确。选项B是普通陈述句，不够准确表达强调语气；选项C缺少关系词；选项D缺少that。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('398aa411-6662-5244-ac86-2090531f6908', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '下列哪个选项正确翻译了“无论你走到哪里，我都会支持你”？', 'choice', '["A. Wherever you go, I will support you.", "B. No matter where do you go, I will support you.", "C. Where you go, I will support you.", "D. Whatever you go, I will support you."]', 'A', '中文“无论……都……”对应英语的“wherever/whatever/no matter where”等状语从句。选项A正确使用了Wherever引导的让步状语从句。选项B语序错误（应为No matter where you go），选项C缺少“无论”含义，选项D中Whatever使用不当（应用Wherever）。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0d12b7a7-5ddd-5da5-85f9-50a2b2a4257f', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '翻译“虽然他很累，但他还是完成了工作”时，可以使用“Although he was tired, but he finished the work.”', 'choice', '["A. 正确", "B. 错误"]', 'B', '英语中although和but不能同时使用，因为although已表示让步关系。正确译文应为“Although he was tired, he finished the work.”或“He was tired, but he finished the work.”。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('a3efbcdf-37cb-557f-b0ca-63e48aa7743d', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在翻译“他跑得很快，以至于没人能追上他”时，应使用“so...that...”句式。', 'choice', '["A. 正确", "B. 错误"]', 'A', '中文“如此……以至于……”对应英语的“so...that...”结构，表示结果。正确译文为“He ran so fast that no one could catch up with him.”，这是四级翻译中的常见句式。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('7dab0e7d-0b86-5933-b65d-c8dc967f50c7', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '翻译“她不仅会唱歌，还会跳舞”时，可以使用“Not only she can sing, but also she can dance.”', 'choice', '["A. 正确", "B. 错误"]', 'B', '当not only位于句首时，主句需要部分倒装。正确译文应为“Not only can she sing, but also she can dance.”，这是倒装句式的常见考点。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('cc106926-b2a6-51f9-a598-3427c1bc27de', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '翻译“众所周知，中国是一个历史悠久的国家。”应使用句式：______ is known to all that China is a country with a long history.', 'fill', NULL, 'It', '中文“众所周知”对应英语的“It is known to all that...”形式主语结构，其中It作形式主语，真正的主语是that从句。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('687cac4d-aee7-5875-8a7c-6cec25869080', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '翻译“这本书值得一读”时，应使用句式：This book is worth ______.', 'fill', NULL, 'reading', '固定搭配“be worth doing”表示“值得做某事”，其中doing用主动形式表示被动含义。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('6602d1cc-3533-5740-8955-b526eaa8ce4f', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '翻译“他昨天没有来上课，因为他生病了”时，应使用______从句连接原因。', 'fill', NULL, 'because/状语', '中文“因为”表示原因，汉译英时应使用because引导的原因状语从句。完整译文为“He didn''t come to class yesterday because he was ill.”', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('5fc89c7b-0e38-5e10-bbc0-f5320234dc1f', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '翻译“我们正在考虑如何解决这个问题”时，应使用“疑问词+______”结构。', 'fill', NULL, 'to do/不定式', '英语中“疑问词+不定式”结构可作宾语，相当于一个宾语从句。完整译文为“We are considering how to solve this problem.”', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('5ab169be-535f-540c-a256-b6bd345b6c3b', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '翻译“他坚持要和我一起去”时，应使用句式：He insisted on ______ with me.', 'fill', NULL, 'going', '动词短语“insist on”后接动名词作宾语，表示“坚持做某事”。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('dd91f580-56e3-5c72-8fdc-4cf9c905d795', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请将以下中文段落翻译为英文，注意使用合适的汉译英常见句式：

“很多人认为，互联网极大地改变了我们的生活方式。它不仅让信息获取变得更容易，还促进了全球交流。然而，也有人担心，过度使用互联网可能会导致社交孤立。事实上，如何正确使用互联网已经成为一个重要的问题。”', 'coding', NULL, 'Many people believe that the Internet has greatly changed our way of life. Not only has it made information acquisition easier, but it has also promoted global communication. However, some people worry that overuse of the Internet may lead to social isolation. In fact, how to use the Internet properly has become an important issue.', '解题思路：
1. 第一句“很多人认为”使用主谓宾结构+that宾语从句，是基本句式。
2. 第二句“不仅……还……”使用not only位于句首的倒装句式，注意主谓倒装。
3. 第三句“然而，也有人担心”使用However连接，worry后接that宾语从句。
4. 第四句“事实上”用In fact开头，“如何正确使用互联网”使用“疑问词+不定式”结构作主语。
5. 整体注意时态一致性，使用现在完成时和一般现在时。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('dc297b9e-8730-5e98-bd04-91dbaa28a4be', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请使用形式主语“it”的句式翻译以下句子：

“对我们来说，掌握一门外语是非常重要的。”', 'coding', NULL, 'It is very important for us to master a foreign language.', '解题思路：
1. 中文“对我们来说，……是非常重要的”中，“非常重要”是表语，“掌握一门外语”是真正的主语。
2. 英语中为避免主语过长，常用it作形式主语，将真正的主语后置为不定式短语。
3. 句式结构：It is + adj. + for sb. + to do sth.。
4. 注意：for us表示“对我们来说”，to master a foreign language是真正主语。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('13fa32cc-240d-5344-98a0-314d1d8e4fa4', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请将下列中文句子翻译为英文，要求使用定语从句：

“我认识一位老师，他的教学方法非常独特。”', 'coding', NULL, 'I know a teacher whose teaching method is very unique.', '解题思路：
1. 中文“一位老师，他的教学方法”中，“他的”指代老师的所有格关系。
2. 英语中表示“某人的”用关系代词whose引导定语从句。
3. 句式结构：主句 + 关系代词whose + 定语从句。
4. 注意：whose在从句中作定语，修饰teaching method。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('141070d4-6a8a-50a8-927d-d02a1dc464fb', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请将下列中文句子翻译为英文，要求使用被动语态：

“每年都有数百万棵树被种植以改善环境。”', 'coding', NULL, 'Millions of trees are planted every year to improve the environment.', '解题思路：
1. 中文“被种植”提示使用被动语态，且“每年”表示一般现在时。
2. 英语被动语态结构：主语（受动者）+ be + 过去分词 + 其他。
3. “数百万棵树”作主语，“种植”用plant的过去分词planted。
4. “以改善环境”用不定式to improve the environment表示目的。
5. 注意：中文无主句或强调受动者时，常用被动语态。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('7a73bf9a-c00b-597f-a638-e47046088d96', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请将下列中文句子翻译为英文，要求使用强调句式：

“昨天在公园里，我遇见了我的老朋友。”', 'coding', NULL, 'It was yesterday that I met my old friend in the park. / It was in the park that I met my old friend yesterday.', '解题思路：
1. 中文强调“昨天”或“在公园里”，需使用“It is/was...that...”强调句式。
2. 强调时间“昨天”时，将yesterday放在It was之后，其余部分放在that之后。
3. 强调地点“在公园里”时，将in the park放在It was之后。
4. 注意：强调句式中，that后的部分用陈述语序，且不能省略that。
5. 两种译法均可，取决于强调的重点。', 'easy', NULL, NULL, '汉译英常见句式', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('bb6cfe1d-0e76-54de-a243-756d89751bc4', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '四级作文中，哪一部分通常用于引入话题并表明观点？', 'choice', '["A. 开头段", "B. 主体段", "C. 结尾段", "D. 过渡段"]', 'A', '根据四级作文模板与结构，开头段的功能是引入话题并表明观点，主体段用于展开论证，结尾段用于总结观点。', 'easy', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('2c17cbc5-a888-57ea-a0d1-79f9726df1c2', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在四级作文的主体段中，通常采用哪种论证结构？', 'choice', '["A. 主题句+例证+解释", "B. 现象+观点+总结", "C. 开头+过渡+结尾", "D. 背景+问题+建议"]', 'A', '四级作文主体段常用“主题句+例证+解释”的论证链，这样能确保逻辑连贯、论据充分。', 'easy', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('b14ed53e-f6d9-57b4-a554-c7b0a88f8ddb', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '以下哪种句式属于四级作文模板中的高级句式？', 'choice', '["A. 简单句", "B. 定语从句", "C. 祈使句", "D. 感叹句"]', 'B', '定语从句、倒装句等复杂句式被视为高级句式，能提升语言档次，而简单句、祈使句、感叹句相对基础。', 'easy', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('47e4693b-924d-5f6a-97b6-230ec0dff58f', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '四级作文评分标准中，哪一项不属于主要关注点？', 'choice', '["A. 内容完整", "B. 结构清晰", "C. 字数达标", "D. 语言准确"]', 'C', '四级作文评分主要关注内容完整、结构清晰、语言准确和逻辑连贯，字数虽有一定要求，但不是核心评分标准。', 'easy', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('20fffc47-c6de-55c2-9301-72f600205141', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在四级作文结尾段，通常使用的收束方式是什么？', 'choice', '["A. 提出新观点", "B. 重复开头句", "C. 总结+建议或展望", "D. 列举更多例子"]', 'C', '结尾段一般用“总结+建议或展望”来收束，避免引入新观点或简单重复，确保文章结构完整。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('af39d120-f8cb-5d84-8114-e609403c2c1d', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '四级作文模板要求考生完全背诵固定套话，不能替换内容。', 'choice', '["A. 正确", "B. 错误"]', 'B', '模板并非死记硬背的套话，而是帮助考生快速组织思路的工具，内容需根据题目灵活替换，避免千篇一律。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('fbb60828-b444-5907-bc2a-0bfca5be86b1', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '四级作文的“三段式”结构通常包括开头段、主体段和结尾段。', 'choice', '["A. 正确", "B. 错误"]', 'A', '“三段式”结构是四级作文最常见的布局，包含开头段（引入话题和观点）、主体段（展开论证）和结尾段（总结观点）。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('693bbd51-66fc-5259-9250-2e85659b380f', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '四级作文中，过渡词的使用有助于提升逻辑连贯性。', 'choice', '["A. 正确", "B. 错误"]', 'A', '过渡词（如however, therefore, moreover）能连接段落和句子，使文章逻辑更清晰，是结构的重要组成部分。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('bfd40fb5-8667-5d04-a1dd-77ab066966e1', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '四级作文的主体段可以随意写，不需要主题句。', 'choice', '["A. 正确", "B. 错误"]', 'B', '主体段通常需要主题句来明确段落中心，再辅以例证和解释，否则容易导致内容松散或跑题。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:45.745114+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('3113b099-aa89-5c0e-a903-415f2f6f32f7', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在四级作文中使用倒装句可以提升语言档次，但需注意语法正确。', 'choice', '["A. 正确", "B. 错误"]', 'A', '倒装句属于高级句式，能增强表达效果，但若使用不当会造成语法错误，因此需灵活且准确地运用。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('1609536a-9c7a-5364-aa74-b40569cd5416', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '四级作文模板的核心原理是“___思维框架”，通过预设段落功能减少考场思考时间。', 'fill', NULL, '标准化', '模板的核心原理是“标准化思维框架”，帮助考生快速组织思路，确保逻辑清晰。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('518628a4-7250-513f-b3aa-5cfe2517af01', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在四级作文开头段，常用的模式是“现象+___”。', 'fill', NULL, '观点', '开头段常用“现象+观点”模式，先描述背景或问题，再明确表达自己的立场。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('8b0e931c-a791-5f80-9a37-fc6b59841467', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '四级作文的“四段式”结构通常比“三段式”多出一个___段。', 'fill', NULL, '过渡', '“四段式”在“三段式”基础上增加一个过渡段或独立论证段，使结构更丰富。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('712020e3-5f4c-55c2-90f7-b135dfb8fff5', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在主体段论证中，“主题句+例证+___”是常见的逻辑链。', 'fill', NULL, '解释', '主体段论证链为“主题句+例证+解释”，先提出观点，再用例子支持，最后解释其意义。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d8bce30f-83bc-576d-84f5-4d03870c5965', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '四级作文评分中，___连贯是确保文章不跑题的关键因素之一。', 'fill', NULL, '逻辑', '逻辑连贯是评分标准之一，通过合理使用模板和过渡词，能避免文章内容跳跃或断层。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('94db9140-bd16-5a40-84e0-1acd35f08b18', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请根据以下题目，写出一篇完整的四级作文开头段和主体段（至少一段），要求使用“现象+观点”开头，主体段包含主题句和例证。题目：Should College Students Take Part-Time Jobs?', 'coding', NULL, '开头段：Nowadays, an increasing number of college students choose to take part-time jobs during their study. Some people argue that this practice distracts students from academic work, while others believe it provides valuable experience. From my perspective, taking part-time jobs is beneficial for college students. 
主体段：First of all, part-time jobs help students develop practical skills. For example, a student working as a tutor can improve communication and problem-solving abilities. These skills are not only useful for future careers but also enhance personal growth. Therefore, the experience gained from part-time jobs outweighs potential drawbacks.', '开头段先描述现象（越来越多大学生做兼职），然后引出两种观点，最后表明自己的立场（利大于弊）。主体段以主题句“兼职有助于培养实用技能”开头，用家教例子支撑，并解释其意义，符合“主题句+例证+解释”结构。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('98784e8e-52a0-5234-b673-e640a5c515ac', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请分析以下作文段落是否符合四级作文模板要求，并指出问题：''I think part-time jobs are good. Many students do them. They can make money. It is very important. So I agree.''', 'coding', NULL, '该段落不符合四级作文模板要求。问题包括：1）缺乏主题句，观点表达过于简单；2）没有具体例证或解释，论证单薄；3）句式单一，全部使用简单句，缺乏过渡词和高级句式；4）逻辑跳跃，未形成“主题句+例证+解释”的论证链。改进建议：可改写为 ''In my opinion, part-time jobs offer significant benefits to college students. For instance, a student working as a waiter can learn time management and teamwork. This experience not only provides financial support but also prepares them for future careers. Therefore, I believe part-time jobs are highly beneficial.''', '原段落内容散乱，未使用模板结构，导致逻辑不清。改进后的段落有明确主题句、例证和解释，符合四级作文结构要求。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('d22fd401-24de-5595-9f4c-364894379069', '25067395-cefc-5ade-9275-b149a9c9f967', 'ee457af5-4c72-5d64-8d8f-3e11bf82f0f7', '在Java中，所有类的根父类是___。', 'fill', NULL, 'Object', 'Object类是Java类层次结构的根类，所有类都直接或间接继承自它。', 'hard', NULL, NULL, 'final关键字与Object类', '2026-07-05T11:59:46.520832+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('70ad8085-fb84-542d-9a6d-686012da4acc', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请修改以下结尾段，使其符合四级作文模板要求：''In conclusion, part-time jobs are good. I hope everyone do it. That is all.''', 'coding', NULL, '修改后：In conclusion, part-time jobs bring numerous advantages to college students, such as skill development and financial independence. Therefore, I strongly recommend that students seize these opportunities to enrich their campus life and prepare for the future. Only by balancing work and study can they achieve holistic growth.', '原结尾段过于简单，缺乏总结和升华。修改后先总结观点（好处），再提出建议（推荐抓住机会），最后用倒装句（Only by...）提升语言档次，符合“总结+建议或展望”的模板要求。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0a05e099-70cd-563d-b3bf-e2ff3be4ac82', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请根据四级作文模板，为题目 ''The Importance of Environmental Protection'' 设计一个完整的四段式结构（只需写出各段主题句）。', 'coding', NULL, '第一段（开头段）：With the rapid development of industry, environmental problems have become increasingly severe, and it is urgent for everyone to take action. From my perspective, environmental protection is of great significance to both human health and the planet''s sustainability. 
第二段（主体段1）：First and foremost, environmental protection directly affects public health. For example, air pollution caused by factories can lead to respiratory diseases, highlighting the need for stricter regulations. 
第三段（主体段2）：Moreover, preserving the environment ensures the long-term survival of ecosystems. Without clean water and soil, agriculture and wildlife would collapse, threatening food security. 
第四段（结尾段）：In conclusion, environmental protection is not only a personal responsibility but also a global necessity. Governments and individuals should work together to adopt sustainable practices, so that future generations can enjoy a healthy planet.', '该结构采用四段式：开头段引入话题并表明观点，两个主体段分别从公共健康和生态系统角度论证，结尾段总结并提出合作建议。每段都有清晰的主题句，符合模板要求。', 'medium', NULL, NULL, '四级作文模板与结构', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ea44ef21-047d-5cc9-9815-ea59c997cefc', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '图表作文的核心写作要求是什么？', 'choice', '["A. 罗列图表中的所有数据", "B. 客观描述关键数据趋势并进行分析", "C. 只描述图表标题", "D. 加入大量个人情感"]', 'B', '图表作文要求客观准确地转述关键数据趋势，并在此基础上进行逻辑分析，而非简单罗列所有数据或加入个人情感。', 'medium', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ebf23f77-2f5f-53dd-be6a-e296811eba92', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '图表作文的“三段式”结构正确顺序是？', 'choice', '["A. 分析-描述-总结", "B. 描述-分析-总结", "C. 总结-描述-分析", "D. 描述-总结-分析"]', 'B', '图表作文遵循“描述-分析-总结”的三段式结构：第一段描述数据趋势，第二段分析原因，第三段总结或预测。', 'medium', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('3f3ad2aa-931f-58a1-a1b9-c2c5d38ac53b', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '以下哪个句型适合用于描述数据上升？', 'choice', '["A. the number decreased sharply", "B. the number remained stable", "C. the number increased dramatically", "D. the number fluctuated wildly"]', 'C', '“increased dramatically”表示急剧上升，符合描述数据上升的句型。其他选项分别表示下降、稳定和波动。', 'medium', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c1867fbd-7c98-553e-80b3-becc2b21cb6b', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在分析数据变化原因时，通常不推荐使用哪种方式？', 'choice', '["A. 从经济发展角度分析", "B. 从政策影响角度分析", "C. 引入图表中未出现的新数据", "D. 从社会观念转变角度分析"]', 'C', '分析原因时应基于图表数据合理推断，不应引入图表中未出现的新数据，以免偏离主题。', 'medium', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('dd159fd6-f27d-593b-813b-80212a623a8b', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '图表作文的第三段（总结段）应避免什么？', 'choice', '["A. 概括总体趋势", "B. 提出个人预测", "C. 引入新数据", "D. 给出合理建议"]', 'C', '总结段应简要概括图表反映的情况或提出预测/建议，但不应引入新数据，以免破坏文章结构。', 'medium', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c4d84c86-eaa1-5008-96d8-b98c852e7061', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '图表作文中，描述数据时应该使用“as is shown in the chart”等固定句型。', 'choice', '["A. 正确", "B. 错误"]', 'A', '这类句型是图表作文的常用表达，能清晰引出图表信息，符合写作规范。', 'medium', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('105df98b-11ae-52f7-9e2b-2cab39380884', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '图表作文可以只描述数据，不需要进行分析和总结。', 'choice', '["A. 正确", "B. 错误"]', 'B', '根据“描述-分析-总结”结构，分析和总结是必要部分，仅描述数据不完整。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('38c0cfaa-3bc9-52d8-9f53-5948d7a85a32', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在描述数据时，应关注最显著的变化趋势，而非所有细节。', 'choice', '["A. 正确", "B. 错误"]', 'A', '图表作文要求抓住关键趋势和显著变化，避免罗列所有数据，否则会显得冗长。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('66c7615b-d062-54a6-8f54-abfcfd3dd1d9', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '“the number of... increased dramatically from... to...”适用于描述下降趋势。', 'choice', '["A. 正确", "B. 错误"]', 'B', '该句型中的“increased dramatically”表示上升，不适用于描述下降趋势。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('de0faf38-6383-596e-8c42-48b98553dbcb', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '图表作文的原因分析部分可以使用“Firstly... Secondly...”等连接词。', 'choice', '["A. 正确", "B. 错误"]', 'A', '使用连接词可以使分析条理清晰，是图表作文的常见写作技巧。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('4a414d85-8bac-56b0-99bd-c957b45b629f', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '图表作文的三段式结构为：第一段_____，第二段分析，第三段总结。', 'fill', NULL, '描述', '第一段需要描述图表中的关键数据趋势，因此填空为“描述”。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('4600b62b-98d6-54c3-84d7-510301fbfa8c', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在图表作文中，描述数据平稳不变时常用短语“remained _____”。', 'fill', NULL, 'stable', '“remained stable”表示保持稳定，是描述数据持平的标准表达。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('97b85165-179d-5743-8759-a9aaf153d521', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '图表作文的常见题型包括柱状图、折线图、饼图和_____。', 'fill', NULL, '表格', '四级图表作文通常涉及柱状图、折线图、饼图和表格四种形式。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('a6c3a5f8-3610-5dae-9beb-87297a4ae6d8', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '分析数据变化原因时，常用句型“Several factors _____ to this phenomenon.”。', 'fill', NULL, 'contribute', '“contribute to”表示“导致、促成”，是分析原因的常见搭配。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('cf94dc4e-b043-58fb-8d23-650965ea4155', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '在总结段落中，应避免引入_____，以免破坏文章结构。', 'fill', NULL, '新数据', '总结段应基于已有数据概括或预测，引入新数据会显得突兀且不符合写作规范。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('dccf49d4-6215-515f-9947-c86daa6058d2', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '根据以下图表信息，写一段图表作文的第一段（描述段）：某校2018-2022年图书馆借书量（单位：千册）：2018年120，2019年150，2020年90，2021年110，2022年180。请描述数据趋势。', 'coding', NULL, 'As is shown in the chart, the number of books borrowed from the library of a university from 2018 to 2022 experienced a fluctuating but overall increasing trend. Specifically, the borrowing number increased from 120,000 in 2018 to 150,000 in 2019, but then dropped sharply to 90,000 in 2020. After that, it rose gradually to 110,000 in 2021 and reached a peak of 180,000 in 2022.', '描述段需先概括总体趋势（波动但总体上升），再按时间顺序描述关键变化，包括上升、下降和峰值，使用具体数据支撑。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('3b5af830-a5f8-5232-b7d2-88e901a2a585', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '基于上一题的数据，请写出分析段，解释2020年借书量下降的可能原因（至少两个）。', 'coding', NULL, 'Several factors contribute to the sharp decline in 2020. Firstly, the outbreak of the COVID-19 pandemic forced the university to close its campus, reducing students'' access to the library. Secondly, the shift to online learning might have led students to rely more on digital resources rather than physical books, further decreasing the borrowing number.', '分析段应提出合理的社会或外部因素，如疫情导致校园关闭、线上学习普及等，使用Firstly/Secondly使逻辑清晰。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('160091e2-1c2b-5a57-925c-649dd6d33a01', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请为上述图表写一个总结段，要求概括总体情况并提出一条建议。', 'coding', NULL, 'Overall, the data reflects that the library borrowing number fluctuated but showed a significant recovery by 2022. To maintain this positive trend, the university could consider promoting reading activities and improving the library''s digital services to attract more students.', '总结段先概括总体趋势（波动但恢复），然后提出具体建议（如推广活动或优化服务），避免引入新数据。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('6b86849a-ce49-5b69-99cd-51cc1846e203', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '假设图表显示某城市2020-2023年新能源汽车销量（单位：万辆）：2020年10，2021年25，2022年45，2023年70。请描述其总体趋势并分析原因（至少两个）。', 'coding', NULL, '描述：As is shown in the chart, the sales of new energy vehicles in a city increased dramatically from 100,000 in 2020 to 700,000 in 2023, showing a consistent upward trend. 分析：Several factors contribute to this phenomenon. Firstly, government policies such as subsidies and tax exemptions encouraged consumers to purchase new energy vehicles. Secondly, advances in battery technology improved vehicle range and reduced costs, making them more attractive to the public.', '描述段需突出持续上升的趋势并用数据佐证；分析段从政策和科技两个角度展开，使用连接词增强条理性。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('3d7ac338-3a3d-504b-90fd-7206d8f3d4a1', 'a1fdefb8-b226-59d4-8057-5bca0fa77c59', 'c5c96d16-435b-51e8-b9b9-605cb73cb6f2', '请为以下饼图写一段描述段：某校学生课余活动分布：学习40%，运动25%，社交20%，娱乐15%。', 'coding', NULL, 'As is shown in the pie chart, the distribution of students'' after-class activities is uneven. Learning accounts for the largest proportion at 40%, followed by sports at 25% and socializing at 20%. Entertainment takes up the smallest share, only 15%.', '饼图描述应突出占比最大和最小的部分，使用“account for”“followed by”等表达，数据准确。', 'hard', NULL, NULL, '图表作文写作技巧', '2026-07-05T11:58:46.053358+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('5bd1ab5f-14da-57e6-a13d-9b5610a8cd4f', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '数据结构主要研究的是数据的（ ）。', 'choice', '["A. 逻辑结构和存储结构", "B. 运算和算法", "C. 数据类型和变量", "D. 程序与代码"]', 'A', '数据结构研究数据的逻辑结构（如线性、树形、图形）和物理存储结构（顺序、链式），以及基于这些结构的运算。选项A正确概括了核心内容。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('bc7cb5ef-3043-5d37-adf4-6b12fa437816', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '下列哪一项不是算法的基本特征？', 'choice', '["A. 有穷性", "B. 确定性", "C. 可读性", "D. 输入和输出"]', 'C', '算法的基本特征包括有穷性、确定性、可行性、输入和输出。可读性是好的程序设计要求，但不是算法必须满足的基本特征。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('2a8ecbd0-a174-5b83-9c92-b179cfd5c2d8', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '在数组中进行随机访问操作的时间复杂度是（ ）。', 'choice', '["A. O(1)", "B. O(log n)", "C. O(n)", "D. O(n²)"]', 'A', '数组支持通过下标直接访问元素，无论数组大小，访问时间恒定，因此时间复杂度为O(1)。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('642011c2-44f8-5ae2-9a4b-534e7d6aa962', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '以下数据结构中，属于非线性结构的是（ ）。', 'choice', '["A. 数组", "B. 链表", "C. 栈", "D. 树"]', 'D', '数组、链表、栈都是线性结构，元素之间为一对一关系。树是非线性结构，元素之间存在一对多关系。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('f02be33b-c92d-553b-989e-9ba269c99737', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '算法的时间复杂度取决于（ ）。', 'choice', '["A. 问题的规模", "B. 计算机的运算速度", "C. 编程语言", "D. 编译器的优化程度"]', 'A', '时间复杂度是问题规模n的函数，反映算法执行时间随n增长的变化趋势。计算机速度、编程语言等属于常数因子，不影响时间复杂度量级。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('09ea3953-751e-5f42-a9ff-8cce0828e6cd', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '在单链表中，已知某个结点的指针p，要删除该结点的后继结点，时间复杂度为（ ）。', 'choice', '["A. O(1)", "B. O(log n)", "C. O(n)", "D. O(n²)"]', 'A', '删除p的后继只需将p的next指针指向后继的后继，并释放后继结点，操作步骤固定，与链表长度无关，时间复杂度为O(1)。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('2cbe1ef3-ebd6-558d-9fb2-c4b322d5acd0', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '下列哪种数据结构适合实现LRU缓存淘汰算法？', 'choice', '["A. 数组", "B. 栈", "C. 哈希表+双向链表", "D. 二叉搜索树"]', 'C', 'LRU缓存需要O(1)的查找和O(1)的插入/删除。哈希表提供快速查找，双向链表支持快速移动结点到头部，二者结合完美实现LRU。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c591ea84-f87e-543b-92d6-b88d588a4200', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '大O表示法描述的是算法的（ ）。', 'choice', '["A. 精确运行时间", "B. 最坏情况下的时间增长趋势", "C. 平均运行时间", "D. 最优情况下的时间增长趋势"]', 'B', '大O表示法表示算法时间复杂度的上界，通常指最坏情况下算法执行时间随输入规模增长的趋势。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('2bafa210-faff-5572-b21a-3c336e80f6ea', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '以下关于数据结构的说法，正确的是（ ）。', 'choice', '["A. 数据的逻辑结构独立于存储结构", "B. 数据的存储结构独立于逻辑结构", "C. 逻辑结构与存储结构完全相同", "D. 逻辑结构决定了存储结构"]', 'A', '逻辑结构是数据元素之间的抽象关系，与具体存储无关；同一逻辑结构可以采用不同的存储结构（如顺序或链式）。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('fd1fe995-72ef-5a74-8a90-65795447c2c9', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '在长度为n的有序数组中采用二分查找算法，时间复杂度为（ ）。', 'choice', '["A. O(1)", "B. O(log n)", "C. O(n)", "D. O(n log n)"]', 'B', '二分查找每次将搜索范围缩小一半，因此最多需要log₂(n)次比较，时间复杂度为O(log n)。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('f326bce4-983a-56ed-b864-cb6e640e7e3a', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '数据结构的物理结构包括顺序存储和链式存储两种基本方式。', 'choice', '["A. 正确", "B. 错误"]', 'A', '物理结构（存储结构）主要有顺序存储（连续内存空间）和链式存储（通过指针链接）两种，此外还有索引存储、散列存储等，但基本方式为顺序和链式。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('cdcb7529-d06e-582b-a6ed-be9fb27ffe9b', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '算法的空间复杂度不可能比时间复杂度小。', 'choice', '["A. 正确", "B. 错误"]', 'B', '空间复杂度和时间复杂度是独立衡量的两个维度，不存在必然的大小关系。例如递归算法可能空间复杂度O(n)而时间复杂度O(2ⁿ)。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('9ca74eb0-0604-5472-8121-e3f5df7608a0', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '栈和队列都是线性结构。', 'choice', '["A. 正确", "B. 错误"]', 'A', '栈和队列的元素之间都是一对一的线性关系，栈是后进先出，队列是先进先出，但逻辑结构都属于线性结构。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c8b81344-e7a0-56d8-b0e5-726c0d353532', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '对于同一个问题，使用不同的数据结构，算法的时间复杂度一定不同。', 'choice', '["A. 正确", "B. 错误"]', 'B', '不同的数据结构可能导致不同算法复杂度，但也可能相同。例如查找操作，使用有序数组（二分查找O(log n)）和平衡二叉搜索树（O(log n)）复杂度相同。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('5dde51bd-14f9-5f10-8c2c-72fba1b75093', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '算法必须具有有穷性，即必须在执行有限步之后终止。', 'choice', '["A. 正确", "B. 错误"]', 'A', '有穷性是算法的基本特征之一，指算法必须在执行有限步骤后结束，不能无限循环。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('8bb050d2-f670-519b-84eb-031f943eeef0', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '数据的逻辑结构分为线性结构和___两大类。', 'fill', NULL, '非线性结构', '数据的逻辑结构分为线性结构（一对一）和非线性结构（一对多或多对多，如树、图）。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('23c2a267-e05c-5686-90ad-16d499084582', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '算法的时间复杂度通常用___表示法来描述。', 'fill', NULL, '大O', '大O表示法用于描述算法时间复杂度的渐进上界，即最坏情况下运行时间随输入规模增长的趋势。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('6eec1232-2708-5efe-85c9-d42086227ca7', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '在链表中插入一个结点的时间复杂度为___（已知插入位置的前驱结点）。', 'fill', NULL, 'O(1)', '已知前驱结点时，插入操作只需修改指针指向，与链表长度无关，时间复杂度为O(1)。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0fc2b2c8-02ba-50ad-8b3f-70ecb0a8f0cc', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '哈希表查找操作的平均时间复杂度为___。', 'fill', NULL, 'O(1)', '在理想情况下，哈希函数均匀分布且冲突较少，查找操作只需计算哈希值并访问对应位置，平均时间复杂度为O(1)。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('85380286-b1b8-5f47-88de-8ea0e876dfbe', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '数据结构+___=程序。', 'fill', NULL, '算法', '这是Niklaus Wirth提出的著名公式：程序 = 数据结构 + 算法，强调了二者在程序设计中的核心地位。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('54eab5a4-1207-5b62-aee4-0d0371389623', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '假设需要设计一个学生成绩管理系统，要求能够快速按学号查找学生成绩，同时支持频繁的添加和删除学生操作。请分析应选择哪种数据结构？并说明理由。', 'coding', NULL, '参考答案：选择哈希表（或基于哈希表的结构，如unordered_map）。理由：1. 按学号查找：哈希表通过哈希函数直接定位，平均时间复杂度O(1)；2. 添加和删除：哈希表插入和删除操作平均时间复杂度也为O(1)，无需移动元素；3. 相比数组（查找O(1)但插入删除O(n)）和链表（插入删除O(1)但查找O(n)），哈希表能同时满足三个需求。如果对顺序遍历有要求，可结合双向链表（如C++ unordered_map内部实现采用哈希表+链表）。', '解题思路：首先分析问题需求——快速查找（学号作为key）、频繁插入删除。然后对比常见数据结构：数组查找快但插入删除慢；链表插入删除快但查找慢；二叉搜索树查找、插入删除平均O(log n)，但不如哈希表常数时间。哈希表在平均情况下所有操作均为O(1)，是最优选择。需注意哈希函数设计及冲突处理。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('e1b1a6f3-f776-58c6-a041-536a47ce8dfb', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '请用大O表示法分析以下代码段的时间复杂度，并说明分析过程。

int sum = 0;
for (int i = 0; i < n; i++) {
    for (int j = 0; j < n; j++) {
        sum += i * j;
}
}', 'coding', NULL, '参考答案：时间复杂度为O(n²)。分析过程：外层循环执行n次，每次外层循环中内层循环执行n次，因此总操作次数为n * n = n²。每次内层循环执行常数时间操作（加法与乘法），故总时间复杂度为O(n²)。', '解题思路：嵌套循环的时间复杂度等于各层循环次数的乘积。外层循环变量i从0到n-1共n次，内层循环变量j从0到n-1共n次，因此总迭代次数为n²。循环体内部为常数时间操作，因此整体为O(n²)。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('b3677398-5789-534c-8ee6-391edc6883c8', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '已知一个数组A[0..n-1]中存储了无序整数，请设计一个算法找出数组中的最大值，并分析其时间复杂度和空间复杂度。', 'coding', NULL, '参考答案：
算法步骤：
1. 初始化max = A[0]
2. 遍历i从1到n-1：
     如果A[i] > max，则更新max = A[i]
3. 返回max
时间复杂度：O(n)，因为需要遍历整个数组一次。
空间复杂度：O(1)，只使用了常数个额外变量（max和循环变量）。', '解题思路：遍历法是最直接的求解最大值方法。通过维护一个当前最大值，逐个比较即可。由于每个元素必须至少访问一次才能确定最大值，因此时间复杂度下界为O(n)。空间上只需常数个变量。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('b017bc1d-6aa0-5608-aa3a-0d0bd7f59327', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '对n个元素进行冒泡排序，最坏情况下需要比较的次数为___（用n表示）。', 'fill', NULL, 'n(n-1)/2', '冒泡排序最坏情况（逆序）下，第一趟比较n-1次，第二趟n-2次，...，最后一趟1次，总和为n(n-1)/2。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('fcd157f8-0cd4-51de-a30e-eae15d3fac36', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '二分查找的空间复杂度（迭代实现）为___。', 'fill', NULL, 'O(1)', '迭代二分查找仅需几个指针变量（如left, right, mid），空间需求与n无关，故为O(1)。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('22e6ebad-c842-5f3d-b85d-de5b200dcb8c', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '已知顺序表L长度为n，在第i个位置插入元素，需要移动的元素个数为___。', 'fill', NULL, 'n-i+1', '插入位置i，从i到n的元素都要后移，共n-i+1个。', 'hard', NULL, NULL, '线性表的定义与操作', '2026-07-05T11:58:46.943153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('0f0b9405-3ef4-5313-b78f-b3b2397f2c20', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '请解释“数据结构+算法=程序”这一公式的含义，并举例说明。', 'coding', NULL, '参考答案：该公式由计算机科学家Niklaus Wirth提出，强调程序是由数据结构和算法共同构成的。数据结构决定了数据如何组织和存储，算法决定了如何操作和处理这些数据，二者缺一不可。例如，实现一个电话簿程序：选择哈希表作为数据结构（存储姓名和电话号码），算法包括添加联系人（调用哈希插入）、查找联系人（调用哈希查找）等。如果没有合适的数据结构，查找可能很慢；如果没有算法，数据无法被有效操作。', '解题思路：先解释公式含义，指出数据结构和算法在程序中的角色。然后通过具体例子（如电话簿、学生管理系统）说明二者如何协同工作。最后强调好的程序需要精心选择数据结构和设计高效算法。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('480e7419-4d38-5b92-9883-8bf1622cdebb', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '比较顺序存储和链式存储的优缺点，并分别给出一个适合使用该存储结构的应用场景。', 'coding', NULL, '参考答案：
顺序存储：
- 优点：支持随机访问（O(1)），存储密度高（不需要额外指针空间），局部性好。
- 缺点：插入和删除需要移动大量元素（O(n)），需要预先分配固定大小的连续空间，扩容成本高。
- 适用场景：需要频繁按索引访问、很少插入删除的场景，如数组实现的静态查找表。
链式存储：
- 优点：插入和删除方便（O(1)已知位置），空间动态分配，不需要连续内存。
- 缺点：不支持随机访问（查找需遍历O(n)），每个结点需额外存储指针，存储密度低。
- 适用场景：频繁插入删除、不需要随机访问的场景，如任务调度队列。', '解题思路：从访问效率、插入删除效率、空间利用率、内存分配方式等维度对比两种存储结构。顺序存储以连续内存为基础，链式存储以指针为基础，理解其本质差异即可推导优缺点。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('740dbcbe-e4c7-5c06-a874-1944f02aa300', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '设计一个算法，判断一个字符串是否回文（正读反读相同），要求时间复杂度O(n)、空间复杂度O(1)。请写出算法步骤并分析复杂度。', 'coding', NULL, '参考答案：
算法步骤：
1. 初始化两个指针i=0, j=n-1（n为字符串长度）
2. 当i < j时循环：
     如果s[i] != s[j]，则返回false
     i++，j--
3. 循环结束返回true
时间复杂度：O(n)，每个字符最多比较一次。
空间复杂度：O(1)，只使用了两个指针变量。', '解题思路：使用双指针从两端向中间遍历，比较对称位置的字符。若全部相等则为回文，否则不是。该方法避免了额外数组或栈的空间开销，满足空间O(1)要求。', 'easy', NULL, NULL, '数据结构与算法概述', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('1c3871f3-444d-5184-8af5-c30ccb297e49', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '下列哪个复杂度表示算法运行时间随输入规模增长最快？', 'choice', '["A. O(1)", "B. O(log n)", "C. O(n²)", "D. O(2ⁿ)"]', 'D', 'O(2ⁿ)是指数增长，远快于多项式O(n²)和对数O(log n)，常数O(1)最慢。', 'easy', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.371428+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('161ddf0f-8e06-5080-933c-0e06ebe35c4e', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '一个算法中，基本操作执行次数为 T(n)=3n²+5n+2，其时间复杂度为？', 'choice', '["A. O(n)", "B. O(n²)", "C. O(n log n)", "D. O(3n²)"]', 'B', '大O表示法忽略常数因子和低阶项，只保留最高阶项n²，因此为O(n²)。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('73a2e46e-f58a-5916-a6eb-40625a61453a', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '对于长度为n的数组进行二分查找，最坏情况下的时间复杂度是？', 'choice', '["A. O(1)", "B. O(log n)", "C. O(n)", "D. O(n log n)"]', 'B', '二分查找每次将搜索区间减半，最坏需log₂n次比较，故时间复杂度O(log n)。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('cc497231-5502-5def-8086-a136e3831024', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '下列排序算法中，空间复杂度为O(1)的是？', 'choice', '["A. 归并排序", "B. 快速排序", "C. 插入排序", "D. 堆排序"]', 'C', '插入排序是原地排序，仅需常数个额外变量，空间复杂度O(1)；归并O(n)，快排O(log n)（递归栈），堆排O(1)但此处插入排序更典型。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('746e966d-e1f1-506b-85c3-ed2ac1592600', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '递归算法计算斐波那契数列第n项（朴素递归实现），时间复杂度为？', 'choice', '["A. O(n)", "B. O(log n)", "C. O(2ⁿ)", "D. O(n²)"]', 'C', '朴素递归斐波那契计算F(n)=F(n-1)+F(n-2)，形成指数级递归树，时间复杂度O(2ⁿ)。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('b5f910cf-cb88-553d-80be-3c29eb12822a', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '大O符号表示算法实际运行时间的具体数值。', 'choice', '["A. 正确", "B. 错误"]', 'B', '大O符号描述的是算法执行时间随输入规模增长的趋势，而非具体运行时间。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('2742b5e2-4100-5614-9190-7be6c0614c2e', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '空间复杂度为O(n)的算法一定比空间复杂度为O(1)的算法占用更多内存。', 'choice', '["A. 正确", "B. 错误"]', 'B', 'O(n)表示空间需求随n线性增长，当n很小时，O(n)算法可能占用内存少于O(1)算法（O(1)常量可能较大），但增长趋势上O(n)最终会超过。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('df18d62c-42da-5db1-a635-cff3e84061de', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '所有递归算法的空间复杂度都与递归深度成正比。', 'choice', '["A. 正确", "B. 错误"]', 'A', '递归调用会使用栈空间，每次调用压栈，深度越大占用空间越多，因此空间复杂度通常与递归深度线性相关。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('1f8d7bde-89b5-5b79-9e02-76bd26e97742', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '两个算法的时间复杂度分别为O(n)和O(n²)，对于所有输入规模，O(n)算法总是比O(n²)算法快。', 'choice', '["A. 正确", "B. 错误"]', 'B', '大O表示渐近行为，当n较小时，常数因子可能导致O(n²)算法实际更快，例如100n vs 0.1n²，在n<1000时100n可能更大。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('8b1009de-54c4-5033-8639-6b96d01fc848', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '用大O表示法分析空间复杂度时，通常只考虑可变空间，不考虑固定空间。', 'choice', '["A. 正确", "B. 错误"]', 'A', '固定空间（如代码、常量）不随输入规模变化，因此在大O分析中只关注随n增长的可变空间。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('9f85c96b-4bbe-5c3e-a2e5-8216d4da8927', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '分析以下代码的时间复杂度：
for(i=0; i<n; i++)
    for(j=0; j<n; j++)
        a[i][j]=0;
时间复杂度为___。', 'fill', NULL, 'O(n²)', '外层循环n次，内层循环n次，每次执行常数操作，总执行次数n*n=n²，故为O(n²)。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('68ad25dd-b05d-5fe3-9859-2b81ee1262e8', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '一个算法的空间复杂度为O(n)，若输入规模n=100时占用1KB内存，则n=1000时预计最多占用___KB内存（假设线性增长）。', 'fill', NULL, '10', '空间复杂度O(n)表示内存与n成正比，n扩大10倍，内存也扩大10倍，即10KB。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('1172f34e-6d10-5348-953c-61e0aefdf31c', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '计算以下递归函数的时间复杂度：
int f(int n){
    if(n<=1) return 1;
return f(n-1)+f(n-1);
}
时间复杂度为___。', 'fill', NULL, 'O(2ⁿ)', '递归式T(n)=2T(n-1)+O(1)，解为T(n)=O(2ⁿ)，每次调用产生两个子问题，深度n。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('c3e96091-a336-5fd4-9f81-e2174f076b4c', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '编写一个函数，计算给定数组（长度为n）中所有元素之和。请分析该函数的时间复杂度和空间复杂度，并说明理由。', 'coding', NULL, '函数实现：
int sum(int arr[], int n) {
    int total = 0;
for(int i=0; i<n; i++)
        total += arr[i];
return total;
}
时间复杂度：O(n)，因为循环执行n次，每次加法操作O(1)。
空间复杂度：O(1)，仅使用固定数量的变量（total, i），不随n变化。', '解题思路：遍历数组累加，基本操作次数与n线性相关；额外空间为常数，故时空分别为O(n)和O(1)。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('13925fda-5b4e-56b0-bbd8-749382074833', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '分析快速排序（随机选取基准）的平均时间复杂度和最坏时间复杂度，并说明其空间复杂度（递归实现）。', 'coding', NULL, '平均时间复杂度：O(n log n)，因为基准大致将数组分成两半，递归深度log n，每层划分需O(n)。
最坏时间复杂度：O(n²)，当每次选中的基准都是最小或最大元素时，划分极不平衡，退化为O(n²)。
空间复杂度：O(log n)（平均），最坏O(n)，递归栈深度等于递归调用深度。', '解题思路：快排性能依赖基准选择，随机化可避免最坏情况，但理论上最坏仍存在；递归栈空间与深度一致。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('65cc994d-1b23-58e3-ab4e-2370ba6910e6', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '给定一个n×n的矩阵，写出算法计算其转置矩阵，并分析时间复杂度和空间复杂度。', 'coding', NULL, '算法：
for(i=0; i<n; i++)
    for(j=i+1; j<n; j++)
        swap(A[i][j], A[j][i]);
时间复杂度：O(n²)，因为内层循环执行约n²/2次，忽略常数后为O(n²)。
空间复杂度：O(1)，原地转置，仅使用一个临时变量进行交换。', '解题思路：只遍历上三角矩阵，每个元素交换一次，操作次数与n²成正比；无需额外矩阵存储。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('3ebe4121-f2cf-5b6a-aa3c-458832b58d58', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '比较顺序查找和二分查找的时间复杂度和空间复杂度，并说明在什么情况下应选择顺序查找。', 'coding', NULL, '顺序查找：时间复杂度O(n)，空间复杂度O(1)。
二分查找：时间复杂度O(log n)，空间复杂度O(1)（迭代）或O(log n)（递归）。
选择顺序查找的情况：
1. 数据无序，无法使用二分查找。
2. 数据量很小，O(n)与O(log n)差异不大。
3. 查找次数极少，构建有序结构开销更大。', '解题思路：从复杂度定义出发，比较两者优劣；顺序查找适用场景基于数据特性和实际需求。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('50ac4b63-7a53-5579-9aba-4af8061423f2', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '设计一个算法，判断一个字符串是否为回文（正反读相同），并分析其时间复杂度和空间复杂度。要求空间复杂度为O(1)。', 'coding', NULL, '算法：
bool isPalindrome(char s[], int n) {
    int left=0, right=n-1;
while(left < right) {
        if(s[left] != s[right]) return false;
left++; right--;
}
    return true;
}
时间复杂度：O(n)，最多比较n/2次。
空间复杂度：O(1)，仅使用两个指针变量。', '解题思路：双指针从两端向中间移动，比较字符；无需额外空间，满足O(1)要求。', 'medium', NULL, NULL, '时间复杂度与空间复杂度', '2026-07-05T11:58:46.662309+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('ded2e62b-322e-52cd-b89e-0af1e4cf156a', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '线性表是一种（ ）。', 'choice', '["A. 非线性结构", "B. 树形结构", "C. 线性结构", "D. 集合结构"]', 'C', '线性表是最基本、最常用的一种线性结构，数据元素之间存在一对一的线性关系。', 'medium', NULL, NULL, '线性表的定义与操作', '2026-07-05T11:58:46.943153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('08e373f6-31be-5a89-ac1e-728d698ac97f', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '在顺序存储的线性表中，插入一个元素平均需要移动多少个元素？', 'choice', '["A. n/2", "B. n", "C. (n+1)/2", "D. (n-1)/2"]', 'A', '在长度为n的顺序表中插入一个元素，平均移动次数为n/2。', 'medium', NULL, NULL, '线性表的定义与操作', '2026-07-05T11:58:46.943153+00:00');
INSERT INTO public.questions (id, chapter_id, course_id, content, type, options, answer, explanation, difficulty, knowledge_point, ima_context, topic, created_at) VALUES ('1a07b5f3-ef77-57e7-bd75-d7c964b46f0e', 'e666276c-8fc4-59f7-a084-9bed91eda11d', '0b49df3d-2ca1-5373-befe-4cf212d8db28', '以下哪个是线性表的基本操作？', 'choice', '["A. 排序", "B. 查找最大值", "C. 插入", "D. 合并"]', 'C', '插入是线性表的基本操作之一，其他操作通常属于扩展操作。', 'medium', NULL, NULL, '线性表的定义与操作', '2026-07-05T11:58:46.943153+00:00');
